 .and().element().type(By.id("username"), username)
 .and().element().type(By.id("password"), password)
 .and().element().click(By.id("loginButton"))
 .and().assertThat(By.className("message")).text().isEqualTo(expectedMessage);

 driver.quit();
 }
}
